// Obtener el mensaje, manejando posibles errores si no hay texto
const msg = items[0].json.message || {};
const text = msg.text ? msg.text.toLowerCase() : "";

let responseText = "¡Hola! Selecciona una opción:\n1. Materia\n2. Tutor\n3. Horario libre";

if (text.includes("1") || text.includes("materia")) {
    responseText = "Entendido, consulta de Materia. Por favor, escribe el nombre de la materia.";
} else if (text.includes("2") || text.includes("tutor")) {
    responseText = "Consulta de Tutor. Escribe el nombre de la materia para darte el tutor.";
} else if (text.includes("3") || text.includes("horario")) {
    responseText = "Consulta de Horario. Escribe la materia.";
}

return {
    json: {
        text: responseText
    }
};

